const input = $json

return {
  json: {
    taskKey: String(input.taskKey || '').trim(),
    sessionId: String(input.sessionId || '').trim(),
    chatId: String(input.chatId || '').trim(),
    workerBaseUrl: String(input.workerBaseUrl || '').trim(),
    authorizationHeader: String(input.authorizationHeader || '').trim(),
    sessionStatusPath: String(input.sessionStatusPath || '').trim(),
    messageListPath: String(input.messageListPath || '').trim(),
    latestSentId: String(input.latestSentId || '').trim(),
  },
}

const input = $('Разбираем входные данные').item.json
const statusMap = $json || {}
const sessionStatus = statusMap[input.sessionId] || {}
const statusType = String(sessionStatus.type || '').trim()

return {
  json: { isIdle: statusType === 'idle' },
}

const input = $('Разбираем входные данные').item.json
const isIdle = String($('Проверяем статус сессии').item.json.isIdle) === 'true'
const latestSentId = input.latestSentId
const rawItems = $('Получаем сообщения сессии').all().map((item) => item.json)
const messages = rawItems.flatMap((item) => Array.isArray(item) ? item : [item]).filter(Boolean)

const assistantMessages = messages.filter((message) => String(message.info?.role || '') === 'assistant').sort((left, right) => Number(left.info?.time?.created || 0) - Number(right.info?.time?.created || 0))

const latestAssistant = assistantMessages[assistantMessages.length - 1] || null

let streamProgressText = ''
let newLatestSentId = latestSentId

const newMessages = latestSentId ? assistantMessages.filter((message) => String(message.info?.id || '') > latestSentId) : assistantMessages
for (const message of newMessages) {
  const texts = Array.isArray(message.parts) ? message.parts.filter((part) => String(part.type || '') === 'text').map((part) => String(part.text || part.content || '').trim()).filter(Boolean) : []
  if (texts.length > 0) {
    streamProgressText = texts.join('\n').trim()
    newLatestSentId = String(message.info?.id || '').trim()
  }
}

if (isIdle) {
  if (!latestAssistant) return {
    json: { resultStatus: 'failed', streamProgressText: '', latestSentId: newLatestSentId, taskCompleted: true, replyText: `Задача ${input.taskKey} завершилась без итогового ответа OpenCode.`, taskKey: input.taskKey },
  }

  const assistantError = latestAssistant.info?.error
  if (assistantError) {
    const errorMessage = String(assistantError.data?.message || assistantError.message || assistantError.name || 'OpenCode завершился с ошибкой.')
    return {
      json: { resultStatus: 'failed', streamProgressText: '', latestSentId: newLatestSentId, taskCompleted: true, replyText: `Задача ${input.taskKey} завершилась ошибкой OpenCode: ${errorMessage}`, taskKey: input.taskKey },
    }
  }

  const textParts = Array.isArray(latestAssistant.parts) ? latestAssistant.parts.filter((part) => String(part.type || '') === 'text').map((part) => String(part.text || part.content || '').trim()).filter(Boolean) : []
  const rawText = textParts.join('\n').trim() || JSON.stringify(latestAssistant)

  return {
    json: { resultStatus: 'done', streamProgressText: '', latestSentId: newLatestSentId, taskCompleted: true, replyText: `Задача ${input.taskKey} завершена.\n\n${rawText}`, taskKey: input.taskKey },
  }
}

return {
  json: { resultStatus: 'running', streamProgressText, latestSentId: newLatestSentId, taskCompleted: false, replyText: '', taskKey: input.taskKey },
}
